using CSV
using DataFrames
using Dates
using IRFs
using Test
using LinearAlgebra
using StableRNGs

using JET
@testset "static analysis with JET.jl" begin
    @test isempty(JET.get_reports(report_package(IRFs; target_modules=(IRFs,))))
end

@testset "QA with Aqua" begin
    using Aqua: Aqua
    Aqua.test_all(IRFs; ambiguities=false)
    Aqua.test_ambiguities(IRFs)
end

function get_data()
    path_d = @__DIR__
    data = DataFrame(
        CSV.File(joinpath(path_d, "kilian_kim_original_dataset.csv"); header=false)
    )
    rename!(data, [:CFNAI, :CPI, :PCOM, :FF])
    DY = data[!, :CFNAI][2:end] # CFNAI
    DP = (log.(data[!, :CPI][2:end]) - log.(data[!, :CPI][1:(end - 1)])) * 100  # D(log(CPI))
    DPCOM =
        (
            (log.(data[!, :PCOM][2:end]) - log.(data[!, :CPI][2:end])) -
            (log.(data[!, :PCOM][1:(end - 1)]) - log.(data[!, :CPI][1:(end - 1)]))
        ) * 100 # D(log(real PCOM)): CRB
    FF = data[!, :FF][2:end]  # FedFound
    return [DY DP DPCOM FF]
end

Y = get_data()

## Estimate VAR
v = VAR(Y, 5)

@test IRFs.names(v) == [:Y_1, :Y_2, :Y_3, :Y_4]
@test IRFs.timeindex(v) == 1:IRFs.rawnobs(v)
@test IRFs.rawnobs(v) == IRFs.nobs(v) + IRFs.nlags(v)
@test rawnobs(v) == nobs(v) + nlags(v)
@test nvars(v) == length(v.names)
@test nlags(v) == 5
@test sizes(v) == (nobs(v), nlags(v), nvars(v))
@test companionmatrix(v) == v.F

