@test IRFs.loglikelihood(v) ≈ -1855.70345572
@test lr ≈ inv(I - dropdims(sum(coef(v); dims=3); dims=3))
@test lr ≈ IRFs.longruneffect(v)
@test IRFs.longrunmean(v) == v.longrunmean
@test IRFs.longrunmean(v) ≈ IRFs.longruneffect(v) * IRFs.intercept(v)
