cov_irf = IRFs.effect_cov(v, R, irf.irf)
@test cov_irf[2, :, :] ≈ covirf1
@test cov_irf[3, :, :] ≈ covirf2

R = TriangularRestriction(v, UnitEffect())
irf = impulseresponse(v, R)

@test tril(irf.irf[1, :, :], -1) ≈ R.R.L
@test IRFs.init(R) ≈ R.R.L + Matrix(float(I(nvars(v))))
@test irf.irf[1, :, :] ≈ IRFs.init(R)
@test irf.irf[2, :, :] ≈ Φ₁ * IRFs.init(R)
@test irf.irf[3, :, :] ≈ Φ₂ * IRFs.init(R)

## Simulate
## Normal
rng = StableRNG(1234)
sim = Simulator(
    v,
    500;
    errortype=:normal,
    alpha=0.1,
    beta=0.35,
    omega=1 - 0.1 - 0.35,
    ntransient=floor(Int64, 500),
)
simulate!(rng, sim)
YY = copy(sim.Y)
rng = StableRNG(1234)
simulate!(rng, sim)
sim.Y ≈ YY

## Garch
rng = StableRNG(1234)
sim = Simulator(
    v, 500; errortype=:garch, alpha=0.1, beta=0.35, omega=1 - 0.1 - 0.35, ntransient=500
)
simulate!(rng, sim)
YY = copy(sim.Y)
rng = StableRNG(1234)
simulate!(rng, sim)
sim.Y ≈ YY

## Antithetic
rng = StableRNG(1234)
sim = Simulator(v, 500; errortype=:antithetic, ntransient=500)
simulate!(rng, sim)
YY = copy(sim.Y)
rng = StableRNG(1234)
simulate!(rng, sim)
sim.Y ≈ YY

## Simple Monte Carlo
using Random
rng = Random.Xoshiro(1234)
sim = Simulator(v, 2000; errortype=:normal, initialvalues=:longrunmean, ntransient=5000)
R = TriangularRestriction(v, UnitEffect())
irf0 = impulseresponse(v, R; ci_type=:delta)

## Create a container for the results
empirical_coverage = Array{Float64,4}(undef, (size(irf0.irf)..., 3))
fill!(empirical_coverage, 0.0)

for s in 1:1000
    ## Simulate VAR
    simulate!(rng, sim)
    ## Re-estimate VAR
    vv = VAR(sim.Y, nlags(v))
    ## Impulse response
    irf_s = impulseresponse(vv, R; ci_type=:delta)
    ## Check if the bound based on irf_s contains the true irf
    for j in 1:3
        empirical_coverage[:, :, :, j] .+=
            (irf_s.lb[j] .> irf0.irf) .& (irf_s.ub[j] .< irf0.irf)
    end
end
